// Input Sanitization
const raw = $json.article_text || $json.body || $json.text || "";
const cleanText = raw
  .replace(/<[^>]*>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/\s+/g, ' ')
  .trim();

if (cleanText.length < 300) {
  throw new Error('Input too short. Please provide at least 300 characters.');
}

return { article_text: cleanText, word_count: cleanText.split(' ').length };

// Robust Parsing
const raw = $json.text || $json.content || '';

const extract = (start, end) => {
  const s = raw.split(start)[1];
  if (!s) return 'Content not generated';
  return end ? s.split(end)[0].trim() : s.trim();
};

return {
  linkedin_post: extract('---LINKEDIN---', '---TWITTER---'),
  twitter_thread: extract('---TWITTER---', '---EMAIL---'),
  email_teaser: extract('---EMAIL---', '---INSTAGRAM---'),
  instagram_caption: extract('---INSTAGRAM---', '---YOUTUBE---'),
  youtube_content: extract('---YOUTUBE---', '---SUMMARY---'),
  summary: extract('---SUMMARY---'),
  generated_at: new Date().toISOString(),
  word_count: $json.word_count || 'N/A'
};
